#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
typedef long long LL;inline LL W(const int &s){return 1ll*s*(s-1)>>1;}
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;int head[N],des[N<<1],nxt[N<<1],cgt,siz[N],mxs[N],dep[N],fa[N],top[N],idx[N<<1],cdt,ql[N],qr[N];
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
inline void dfs1(const int &u=1,const int &f=0)
{
	dep[u]=dep[fa[u]=f]+1;siz[u]=1;int mx=0;
	grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
{
	top[idx[ql[u]=++cdt]=u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);idx[qr[u]=++cdt]=u;
}
inline int LCA(int u,int v){while(top[u]^top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];return dep[u]<dep[v]?u:v;}
struct N1{int l,r,t,lc,idx;}q[N];struct N2{int p,u,v;}t[N];bool vis[N];int cnt[N<<1],L,R,Tm,a[N],A[N],n,Q,T;LL Ans,ans[N];
inline void add(const int &v,const int &w){Ans-=W(cnt[v]);cnt[v]+=w;Ans+=W(cnt[v]);}inline void ins(const int &p){add(a[p],vis[p]?-1:1);vis[p]^=1;}
inline void Tadd(){++Tm;int p=t[Tm].p,v=t[Tm].v;if(vis[p])add(a[p],-1),add(v,1);a[p]=v;}
inline void Tmns(){int p=t[Tm].p,u=t[Tm].u;--Tm;if(vis[p])add(a[p],-1),add(u,1);a[p]=u;}
int main()
{
	n=read();int nQ=read();rep(1,n,i)a[i]=A[i]=read();rep(2,n,i)ins(read()+1,read()+1);
	dfs1();dfs2();while(nQ--)
	{
		if(read()==1){int p=read()+1,v=read();t[++T]=(N2){p,A[p],v};A[p]=v;}
		else
		{
			int u=read()+1,v=read()+1;if(ql[u]>ql[v]){int t(u);u=v;v=t;}++Q;
			if(ql[u]<=ql[v]&&qr[v]<=ql[u])q[Q]=(N1){ql[u],ql[v],T,0,Q};else q[Q]=(N1){qr[u],ql[v],T,LCA(u,v),Q};
		}
	}
	std::sort(q+1,q+Q+1,[&](const N1&x,const N1&y){return (x.l>>11)==(y.l>>11)?((x.r>>11)==(y.r>>11)?x.t<y.t:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=L-1;Tm=0;rep(1,Q,i)
	{
		while(R<q[i].r)ins(idx[++R]);while(L>q[i].l)ins(idx[--L]);
		while(R>q[i].r)ins(idx[R--]);while(L<q[i].l)ins(idx[L++]);
		while(Tm<q[i].t)Tadd();while(Tm>q[i].t)Tmns();
		if(q[i].lc)ins(q[i].lc);ans[q[i].idx]=Ans;if(q[i].lc)ins(q[i].lc);
	}
	rep(1,Q,i)printf("%lld\n",ans[i]);return 0;
	
}
